    view, 
    savedProductIds, 
    onSaveToggle, 
    products, 
    customers, 
    addNotification, 
    currentUser, 
    orders,
    users,
    withdrawalRequests,
    faqItems,
    siteSettings,
    categories,
    tickets,
    userTickets,
    userOrders,
    coupons,
    onAddCustomer,
    onUpdateCustomer,
    onDeleteCustomer,
    onAddProduct,
    onUpdateProduct,
    onDeleteProduct,
    onUpdateUser,
    onUpdateOrderStatus,
    onDeleteUser,
    onProcessWithdrawal,
    onSetFaqItems,
    onUpdateSiteSettings,
    onSetCategories,
