const AccountSubPage: React.FC<AccountSubPageProps> = (props) => {
    const { view, currentUser, setHeaderConfig } = props;

    useEffect(() => {
        if (view !== 'adminDashboard') {
            setHeaderConfig(null);
        }
    }, [view, setHeaderConfig]);

    switch (view) {
        case 'editProfile':
            return <EditProfilePage 
                        currentUser={currentUser} 
                        onUpdateUser={props.onUpdateUser} 
                        onDeleteUser={props.onDeleteUser} 
                        addNotification={props.addNotification} 
                   />;
        case 'savedProducts':
            return <SavedProductsPage savedProductIds={props.savedProductIds} onSaveToggle={props.onSaveToggle} products={props.products} />;
        case 'customerDetails':
            return <CustomerDetailsPage 
                        customers={props.customers} 
                        onAddCustomer={props.onAddCustomer} 
                        onUpdateCustomer={props.onUpdateCustomer} 
                        onDeleteCustomer={props.onDeleteCustomer} 
                    />;
        case 'instructions':
            return <InstructionsPage faqItems={props.faqItems} />;
        case 'privacyPolicy':
            return <PrivacyPolicyPage content={""} />; 
        case 'termsAndConditions':
            return <TermsAndConditionsPage content={""} />;
        case 'serviceFees':
            return <ServiceFeesPage content={""} />;
        case 'myTickets':
            return <MyTicketsPage 
                      tickets={props.userTickets} 
                      currentUser={currentUser} 
                      onOpenTicketChat={props.onOpenTicketChat}
                      userOrders={props.userOrders}
                      onInitiateTicketThread={props.onInitiateTicketThread}
                      addNotification={props.addNotification}
                   />;
        case 'adminDashboard':
            return currentUser?.is_admin ? (
                <AdminDashboardPage 
                    products={props.products}
                    onAddProduct={props.onAddProduct}
                    onUpdateProduct={props.onUpdateProduct}
                    onDeleteProduct={props.onDeleteProduct}
                    orders={props.orders}
                    users={props.users}
                    customers={props.customers}
                    onUpdateOrderStatus={props.onUpdateOrderStatus}
                    onDeleteUser={props.onDeleteUser}
                    withdrawalRequests={props.withdrawalRequests}
                    onProcessWithdrawal={props.onProcessWithdrawal}
                    addNotification={props.addNotification}
                    faqItems={props.faqItems}
                    siteSettings={props.siteSettings}
                    onSetFaqItems={props.onSetFaqItems}
                    onUpdateSiteSettings={props.onUpdateSiteSettings}
                    categories={props.categories}
                    onSetCategories={props.onSetCategories}
                    onAdminOrderClick={props.onAdminOrderClick}
                    tickets={props.tickets}
                    onUpdateTicketThreadStatus={props.onUpdateTicketThreadStatus}
                    onAddTicketMessage={props.onAddTicketMessage}
                    onOpenTicketChat={props.onOpenTicketChat}
                    setHeaderConfig={setHeaderConfig}
                    coupons={props.coupons}
                    onAddCoupon={props.onAddCoupon}
                    onUpdateCoupon={props.onUpdateCoupon}
                    onDeleteCoupon={props.onDeleteCoupon}
                    onAdminUpdateOrder={props.onAdminUpdateOrder}
                    view={props.adminView}
                    onViewChange={props.setAdminView}
                    currentUser={currentUser}
                />
            ) : (
                <div className="text-center text-red-500 p-4">لا تملك صلاحيات الوصول إلى لوحة التحكم.</div>
            );
        default:
            return <div className="p-4 text-center text-gray-500">الصفحة غير موجودة.</div>;
    }
};

export default AccountSubPage;

import React from 'react';
import { type Product } from '../../types';
import { BookmarkIcon, CubesStackIcon } from './icons';

interface ProductCardProps {
  product: Product;
  onClick: () => void;
  isSaved: boolean;
  onSaveToggle: (productId: string) => void;
  onAddToCartClick?: (product: Product) => void;
}

const ProductCard: React.FC<ProductCardProps> = ({ product, onClick, isSaved, onSaveToggle }) => {
  const isOutOfStock = product.stock === 0;

  // حساب الربح التقريبي المعروض للمسوق
  const minProfit = product.min_sell_price - product.price;

  return (
    <div 
      onClick={onClick}
      className="bg-white dark:bg-gray-800 rounded-[24px] shadow-sm border border-gray-100 dark:border-gray-700/50 flex flex-col h-full relative group active:scale-[0.97] transition-all duration-300 overflow-hidden"
      role="button"
      aria-label={`عرض تفاصيل ${product.name}`}
    >
      {/* Image Section */}
      <div className="p-1.5">
        <div className="relative w-full aspect-[1/1] rounded-[20px] overflow-hidden bg-gray-50 dark:bg-gray-900/50">
            <img 
                className={`w-full h-full object-cover transition-transform duration-700 group-hover:scale-110 ${isOutOfStock ? 'opacity-40 grayscale' : ''}`} 
                src={product.image_urls[0]} 
                alt={product.name} 
                loading="lazy" 
            />

            {/* Out of Stock Overlay */}
            {isOutOfStock && (
                <div className="absolute inset-0 flex items-center justify-center bg-black/10 backdrop-blur-[2px]">
                    <span className="bg-red-500 text-white text-[10px] font-extrabold px-3 py-1 rounded-full shadow-lg">
                        نفذت الكمية
                    </span>
                </div>
            )}

            {/* Save Button - Floating Top Left */}
            <button 
                onClick={(e) => {
                    e.stopPropagation();
                    onSaveToggle(product.id);
                }}
                className={`absolute top-2 left-2 w-8 h-8 flex items-center justify-center rounded-full backdrop-blur-md shadow-sm transition-all duration-300 z-10
                    ${isSaved 
                        ? 'bg-primary text-white scale-110' 
                        : 'bg-white/80 dark:bg-gray-800/80 text-gray-400 hover:text-primary dark:text-gray-500'
                    }`}
            >
                <BookmarkIcon filled={isSaved} className="w-4 h-4" />
            </button>

            {/* Series Tag - Top Right */}
            {!isOutOfStock && (
                <div className="absolute top-2 right-2 bg-black/60 dark:bg-primary/20 backdrop-blur-md text-white dark:text-primary-light text-[9px] font-bold px-2 py-1 rounded-lg flex items-center gap-1 border border-white/10">
                    <CubesStackIcon className="w-3 h-3" />
                    <span>سيرية</span>
                </div>
            )}
        </div>
      </div>

      {/* Content Section */}
      <div className="px-3 pb-3 flex flex-col flex-grow text-right">
        {/* Category/Subcategory Small Tag */}
        <span className="text-[9px] font-bold text-gray-400 dark:text-gray-500 mt-1 mb-0.5 uppercase tracking-wider">
            {product.category}
        </span>

        {/* Product Title */}
        <h3 className={`text-[13px] font-bold leading-tight line-clamp-2 min-h-[32px] ${isOutOfStock ? 'text-gray-400' : 'text-gray-900 dark:text-white'}`}>
            {product.name}
        </h3>

        {/* Pricing Info */}
        <div className="mt-3 flex flex-col gap-1.5">
            <div className="flex items-baseline justify-start gap-1">
                <span className={`text-lg font-black tracking-tight ${isOutOfStock ? 'text-gray-300' : 'text-primary dark:text-primary-light'}`}>
                    {product.price.toLocaleString()}
                </span>
                <span className="text-[10px] font-bold text-gray-400 uppercase">د.ع</span>
                <span className="text-[9px] font-medium text-gray-400 mr-auto">(سعر الجملة)</span>
            </div>

            {/* Profit Badge/Ribbon */}
            {!isOutOfStock && minProfit > 0 && (
                <div className="bg-green-50 dark:bg-green-900/20 rounded-xl py-1.5 px-2.5 border border-green-100 dark:border-green-800/30 flex items-center justify-between">
                    <span className="text-green-600 dark:text-green-400 text-[10px] font-extrabold">ربحك المقترح</span>
                    <span className="text-green-700 dark:text-green-400 text-[11px] font-black">+{minProfit.toLocaleString()}</span>
                </div>
            )}

            {product.promo && !isOutOfStock && minProfit <= 0 && (
                <div className="bg-orange-50 dark:bg-orange-900/20 rounded-xl py-1.5 px-2.5 border border-orange-100 dark:border-orange-800/30 text-center">
                    <span className="text-orange-600 dark:text-orange-400 text-[10px] font-extrabold">{product.promo}</span>
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

