        );
    }

    return (
        <div className="grid grid-cols-2 gap-4 mt-2">
            {products.map((product) => (
                <ProductCard 
                    key={product.id} 
                    product={product} 
                    onClick={() => onProductClick(product)}
                    isSaved={savedProductIds.includes(product.id)}
