                      <p className="font-black text-gray-800 dark:text-gray-100">{product.series_count} قطع</p>
                  </div>
                  <div className="bg-gray-50 dark:bg-slate-900/50 p-3 rounded-2xl">
                      <p className="text-[10px] font-bold text-gray-400 mb-1">المخزون المتوفر</p>
                      <p className="font-black text-gray-800 dark:text-gray-100">{product.stock} سيرية</p>
                  </div>
              </div>
              <div className="bg-indigo-50/50 dark:bg-indigo-900/10 p-3 rounded-2xl border border-indigo-100/50 dark:border-indigo-800/30">
                  <p className="text-[10px] font-bold text-indigo-400 mb-1">القياسات المتوفرة في السيرية</p>
                  <p className="font-bold text-indigo-700 dark:text-indigo-300 text-sm leading-relaxed">{product.series_sizes}</p>
              </div>
          </div>

          {/* 6. Tabs Section */}
          <div className="space-y-4">
              <div className="flex bg-white dark:bg-gray-800 p-1.5 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
                  <button 
                    onClick={() => setActiveTab('info')}
                    className={`flex-1 py-3 rounded-xl text-sm font-black transition-all ${activeTab === 'info' ? 'bg-primary text-white shadow-lg shadow-primary/20' : 'text-gray-400'}`}
                  >
                      معلومات المنتج
                  </button>
                  <button 
                    onClick={() => setActiveTab('marketing')}
                    className={`flex-1 py-3 rounded-xl text-sm font-black transition-all ${activeTab === 'marketing' ? 'bg-primary text-white shadow-lg shadow-primary/20' : 'text-gray-400'}`}
                  >
                      نص جاهز للنشر
                  </button>
              </div>

              <div className="bg-white dark:bg-gray-800 rounded-3xl p-6 border border-gray-100 dark:border-gray-700 shadow-sm relative group">
                  <button 
                    onClick={() => handleCopy(activeTab === 'info' ? `${product.name}\n${product.description}` : (product.marketing_description || product.promo), 'النص')}
                    className="absolute top-4 left-4 p-2 bg-gray-50 dark:bg-gray-700 text-gray-400 hover:text-primary rounded-xl opacity-0 group-hover:opacity-100 transition-all"
                  >
                      <CopyIcon className="w-5 h-5" />
                  </button>

                  {activeTab === 'info' ? (
                      <div className="space-y-4">
                          <p className="text-gray-600 dark:text-gray-300 text-sm leading-loose">{product.description}</p>
                          {product.details && (
                              <div className="grid grid-cols-1 gap-2 pt-2">
                                  {Object.entries(product.details).map(([key, val]) => (
                                      <div key={key} className="flex justify-between items-center text-xs py-2 border-b border-gray-50 dark:border-gray-700 last:border-0">
                                          <span className="text-gray-400 font-bold">{key}</span>
                                          <span className="text-gray-700 dark:text-gray-200 font-black">{val}</span>
                                      </div>
                                  ))}
                              </div>
                          )}
                      </div>
                  ) : (
                      <div className="space-y-4">
                          <div className="bg-primary/5 p-4 rounded-2xl text-primary text-xs font-bold leading-relaxed mb-4">
                              انسخ هذا النص وضعه في صفحتك على فيسبوك أو انستغرام لجذب الزبائن!
                          </div>
                          <p className="text-gray-700 dark:text-gray-200 text-sm whitespace-pre-wrap leading-loose">
                              {product.marketing_description || product.promo}
                          </p>
                      </div>
                  )}
              </div>
          </div>

          {/* 7. Professional Assets */}
          {product.telegramUrl && (
              <a 
                href={product.telegramUrl} 
                target="_blank" 
                className="flex items-center justify-between bg-[#229ED9] p-4 rounded-3xl text-white shadow-lg shadow-blue-500/20 active:scale-95 transition-all"
              >
                  <div className="flex items-center gap-3">
                      <div className="w-10 h-10 bg-white/20 rounded-2xl flex items-center justify-center">
                          <i className="fa-brands fa-telegram text-2xl"></i>
                      </div>
                      <div className="text-right">
                          <p className="text-xs opacity-80 font-bold">المحتوى الإبداعي</p>
                          <p className="font-black">تحميل الصور والفيديو بدقة عالية</p>
                      </div>
                  </div>
                  <ChevronDownIcon className="w-5 h-5 -rotate-90" />
              </a>
          )}
      </div>

      {/* 8. Fixed Action Bottom Bar */}
      <div className="fixed bottom-0 left-0 right-0 p-4 bg-white/80 dark:bg-slate-900/80 backdrop-blur-xl border-t border-gray-100 dark:border-gray-800 z-50">
          <div className="max-w-lg mx-auto flex items-center gap-3">
              {/* Quantity Selector */}
              <div className="flex items-center bg-gray-100 dark:bg-gray-800 p-1 rounded-2xl border border-gray-200 dark:border-gray-700 h-14">
                  <button onClick={() => setQuantity(q => q + 1)} disabled={quantity >= product.stock} className="w-10 h-full flex items-center justify-center text-primary disabled:opacity-30"><PlusIcon className="w-4 h-4" /></button>
                  <span className="w-10 text-center font-black dark:text-white">{quantity}</span>
                  <button onClick={() => setQuantity(q => Math.max(1, q - 1))} className="w-10 h-full flex items-center justify-center text-gray-400"><MinusIcon className="w-4 h-4" /></button>
              </div>

              {/* Add to Cart Button */}
              <button 
                onClick={handleAddToCart}
                disabled={product.stock === 0}
                className="flex-grow bg-primary text-white h-14 rounded-2xl font-black shadow-xl shadow-primary/30 active:scale-95 transition-all flex items-center justify-center gap-2 disabled:bg-gray-300"
              >
                  <CartIcon className="w-5 h-5" />
                  <span>{product.stock === 0 ? 'نفذت الكمية' : 'إضافة السيريات للسلة'}</span>
              </button>
          </div>
      </div>

      <style>{`
          @keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
          .animate-fade-in { animation: fade-in 0.2s ease-out forwards; }
          .no-scrollbar::-webkit-scrollbar { display: none; }
          .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
    </div>
  );
};

export default ProductDetailsPage;

