import React, { useState, useMemo } from 'react';
import { Product } from '../../types';
import { 
    BookmarkIcon, PlusIcon, MinusIcon, ChevronDownIcon, 
    XMarkIcon, CopyIcon, CartIcon, CubesStackIcon, 
    ShareIcon, TelegramIcon, CheckCircleIcon, WalletIcon 
} from '../common/icons';

const ImageGalleryModal: React.FC<{
  images: string[];
  initialIndex: number;
  onClose: () => void;
  productName: string;
}> = ({ images, initialIndex, onClose, productName }) => {
    const [currentIndex, setCurrentIndex] = useState(initialIndex);

    const goToPrevious = () => setCurrentIndex(prev => (prev === 0 ? images.length - 1 : prev - 1));
    const goToNext = () => setCurrentIndex(prev => (prev === images.length - 1 ? 0 : prev + 1));

    return (
        <div className="fixed inset-0 bg-black/95 z-[100] flex flex-col items-center justify-center animate-fade-in" onClick={onClose}>
            <button onClick={onClose} className="absolute top-6 left-6 text-white p-2 bg-white/10 rounded-full backdrop-blur-md">
                <XMarkIcon className="w-6 h-6" />
            </button>
            <div className="relative w-full h-full flex items-center justify-center p-4">
                 <img src={images[currentIndex]} alt={productName} className="max-h-full max-w-full object-contain rounded-2xl" />
            </div>
            <div className="absolute bottom-10 flex gap-2 overflow-x-auto p-2 no-scrollbar">
                {images.map((img, i) => (
                    <div 
                        key={i} 
                        onClick={(e) => { e.stopPropagation(); setCurrentIndex(i); }}
                        className={`w-14 h-14 rounded-lg overflow-hidden border-2 transition-all ${currentIndex === i ? 'border-primary scale-110' : 'border-transparent opacity-50'}`}
                    >
                        <img src={img} className="w-full h-full object-cover" />
                    </div>
                ))}
            </div>
        </div>
    );
};

interface ProductDetailsPageProps {
  product: Product;
  onAddToCart: (product: Product, size: string) => void;
  addNotification: (message: string) => void;
  isSaved: boolean;
  onSaveToggle: (productId: string) => void;
}

const ProductDetailsPage: React.FC<ProductDetailsPageProps> = ({ product, onAddToCart, addNotification, isSaved, onSaveToggle }) => {
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState<'info' | 'marketing'>('info');
  const [mainImageIdx, setMainImageIdx] = useState(0);
  const [isGalleryOpen, setIsGalleryOpen] = useState(false);

  const handleAddToCart = () => {
    const sizeName = `سيرية (${product.series_count} قطع)`;
    for (let i = 0; i < quantity; i++) {
        onAddToCart(product, sizeName);
    }
  };

  const handleCopy = (text: string, label: string) => {
      navigator.clipboard.writeText(text);
      addNotification(`تم نسخ ${label}`);
  };

  const potentialProfit = (product.min_sell_price - product.price);

  return (
    <div className="bg-gray-50 dark:bg-slate-900 min-h-screen pb-32 font-cairo text-right" dir="rtl">
       {isGalleryOpen && (
            <ImageGalleryModal
                images={product.image_urls}
                initialIndex={mainImageIdx}
                onClose={() => setIsGalleryOpen(false)}
                productName={product.name}
            />
        )}

      {/* 1. Image Showcase Section */}
      <div className="relative bg-white dark:bg-gray-800 rounded-b-[40px] shadow-sm overflow-hidden">
          <div className="aspect-square w-full relative">
              <img 
                src={product.image_urls[mainImageIdx]} 
                alt={product.name} 
                className="w-full h-full object-cover cursor-zoom-in"
                onClick={() => setIsGalleryOpen(true)}
              />

              {/* Floating Buttons */}
              <div className="absolute top-4 left-4 flex flex-col gap-2">
                  <button onClick={() => onSaveToggle(product.id)} className={`w-10 h-10 rounded-full flex items-center justify-center shadow-lg backdrop-blur-md transition-all ${isSaved ? 'bg-primary text-white' : 'bg-white/80 text-gray-600'}`}>
                      <BookmarkIcon filled={isSaved} className="w-5 h-5" />
                  </button>
                  <button className="w-10 h-10 rounded-full bg-white/80 text-gray-600 flex items-center justify-center shadow-lg backdrop-blur-md">
                      <ShareIcon className="w-5 h-5" />
                  </button>
              </div>

              {/* Thumbnails Overlay */}
              <div className="absolute bottom-6 right-4 flex flex-col gap-2">
                  {product.image_urls.map((img, i) => (
                      <button 
                        key={i} 
                        onClick={() => setMainImageIdx(i)}
                        className={`w-12 h-12 rounded-xl border-2 overflow-hidden transition-all bg-white ${mainImageIdx === i ? 'border-primary' : 'border-transparent shadow-sm'}`}
                      >
                          <img src={img} className="w-full h-full object-cover" />
                      </button>
                  ))}
              </div>
          </div>
      </div>

      <div className="px-5 pt-6 space-y-6">
          {/* 2. Main Info Card */}
          <div className="space-y-2">
              <div className="flex justify-between items-start gap-4">
                <h1 className="text-2xl font-black text-gray-900 dark:text-white leading-tight flex-1">
                    {product.name}
                </h1>
                {product.brand && (
                    <span className="bg-gray-100 dark:bg-gray-800 px-3 py-1 rounded-full text-xs font-bold text-gray-500">{product.brand}</span>
                )}
              </div>
              <p className="text-gray-400 text-sm font-bold">القسم: {product.category} {product.subcategory && `> ${product.subcategory}`}</p>
          </div>

          {/* 3. Pricing Dashboard */}
          <div className="grid grid-cols-2 gap-4">
              <div className="bg-white dark:bg-gray-800 p-4 rounded-3xl border border-gray-100 dark:border-gray-700 shadow-sm">
                  <p className="text-[10px] font-black text-gray-400 mb-1 uppercase tracking-wider">سعر الجملة (للسيرية)</p>
                  <div className="flex items-baseline gap-1">
                      <span className="text-2xl font-black text-primary">{product.price.toLocaleString()}</span>
                      <span className="text-[10px] font-bold text-gray-500">د.ع</span>
                  </div>
              </div>
              <div className="bg-green-50 dark:bg-green-900/10 p-4 rounded-3xl border border-green-100 dark:border-green-800/30 shadow-sm">
                  <p className="text-[10px] font-black text-green-600 dark:text-green-400 mb-1 uppercase tracking-wider">ربحك المتوقع</p>
                  <div className="flex items-baseline gap-1">
                      <span className="text-2xl font-black text-green-700 dark:text-green-400">+{potentialProfit.toLocaleString()}</span>
                      <span className="text-[10px] font-bold text-green-600">د.ع</span>
                  </div>
              </div>
          </div>

          {/* 4. Suggested Price (The Telegram Style Bar) */}
          <div className="bg-primary/5 dark:bg-primary/10 border-2 border-dashed border-primary/20 p-4 rounded-[24px] flex justify-between items-center">
              <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-2xl bg-primary text-white flex items-center justify-center">
                      <WalletIcon className="w-5 h-5" />
                  </div>
                  <div>
                      <p className="text-xs font-bold text-gray-500">السعر المقترح للزبون</p>
                      <p className="text-sm font-black text-primary">{product.min_sell_price.toLocaleString()} - {product.max_sell_price.toLocaleString()} د.ع</p>
                  </div>
              </div>
              <button 
                onClick={() => handleCopy(`${product.min_sell_price.toLocaleString()} - ${product.max_sell_price.toLocaleString()} دينار`, 'السعر')}
                className="p-2 text-primary hover:bg-primary/10 rounded-xl transition-colors"
              >
                  <CopyIcon className="w-5 h-5" />
              </button>
          </div>

          {/* 5. Series Info Box */}
          <div className="bg-white dark:bg-gray-800 rounded-3xl p-5 border border-gray-100 dark:border-gray-700 shadow-sm space-y-4">
              <div className="flex items-center gap-2 mb-2">
                  <CubesStackIcon className="w-5 h-5 text-indigo-500" />
                  <h3 className="font-black text-gray-800 dark:text-gray-100">تفاصيل الباكت (السيرية)</h3>
              </div>
              <div className="grid grid-cols-2 gap-4">
                  <div className="bg-gray-50 dark:bg-slate-900/50 p-3 rounded-2xl">
                      <p className="text-[10px] font-bold text-gray-400 mb-1">العدد الإجمالي</p>
                      <p className="font-black text-gray-800 dark:text-gray-100">{product.series_count} قطع</p>
                  </div>
                  <div className="bg-gray-50 dark:bg-slate-900/50 p-3 rounded-2xl">
                      <p className="text-[10px] font-bold text-gray-400 mb-1">المخزون المتوفر</p>
                      <p className="font-black text-gray-800 dark:text-gray-100">{product.stock} سيرية</p>
                  </div>
              </div>
              <div className="bg-indigo-50/50 dark:bg-indigo-900/10 p-3 rounded-2xl border border-indigo-100/50 dark:border-indigo-800/30">
                  <p className="text-[10px] font-bold text-indigo-400 mb-1">القياسات المتوفرة في السيرية</p>
                  <p className="font-bold text-indigo-700 dark:text-indigo-300 text-sm leading-relaxed">{product.series_sizes}</p>
              </div>
          </div>

          {/* 6. Tabs Section */}
          <div className="space-y-4">
              <div className="flex bg-white dark:bg-gray-800 p-1.5 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
                  <button 
                    onClick={() => setActiveTab('info')}
                    className={`flex-1 py-3 rounded-xl text-sm font-black transition-all ${activeTab === 'info' ? 'bg-primary text-white shadow-lg shadow-primary/20' : 'text-gray-400'}`}
                  >
                      معلومات المنتج
                  </button>
                  <button 
                    onClick={() => setActiveTab('marketing')}
                    className={`flex-1 py-3 rounded-xl text-sm font-black transition-all ${activeTab === 'marketing' ? 'bg-primary text-white shadow-lg shadow-primary/20' : 'text-gray-400'}`}
                  >
                      نص جاهز للنشر
                  </button>
              </div>

              <div className="bg-white dark:bg-gray-800 rounded-3xl p-6 border border-gray-100 dark:border-gray-700 shadow-sm relative group">
                  <button 
                    onClick={() => handleCopy(activeTab === 'info' ? `${product.name}\n${product.description}` : (product.marketing_description || product.promo), 'النص')}
                    className="absolute top-4 left-4 p-2 bg-gray-50 dark:bg-gray-700 text-gray-400 hover:text-primary rounded-xl opacity-0 group-hover:opacity-100 transition-all"
                  >
                      <CopyIcon className="w-5 h-5" />
                  </button>

                  {activeTab === 'info' ? (
                      <div className="space-y-4">
                          <p className="text-gray-600 dark:text-gray-300 text-sm leading-loose">{product.description}</p>
                          {product.details && (
                              <div className="grid grid-cols-1 gap-2 pt-2">
                                  {Object.entries(product.details).map(([key, val]) => (
                                      <div key={key} className="flex justify-between items-center text-xs py-2 border-b border-gray-50 dark:border-gray-700 last:border-0">
                                          <span className="text-gray-400 font-bold">{key}</span>
                                          <span className="text-gray-700 dark:text-gray-200 font-black">{val}</span>
                                      </div>
                                  ))}
                              </div>
                          )}
                      </div>
                  ) : (
                      <div className="space-y-4">
                          <div className="bg-primary/5 p-4 rounded-2xl text-primary text-xs font-bold leading-relaxed mb-4">
                              انسخ هذا النص وضعه في صفحتك على فيسبوك أو انستغرام لجذب الزبائن!
                          </div>
                          <p className="text-gray-700 dark:text-gray-200 text-sm whitespace-pre-wrap leading-loose">
                              {product.marketing_description || product.promo}
                          </p>
                      </div>
                  )}
              </div>
          </div>

          {/* 7. Professional Assets */}
          {product.telegramUrl && (
              <a 
                href={product.telegramUrl} 
                target="_blank" 
                className="flex items-center justify-between bg-[#229ED9] p-4 rounded-3xl text-white shadow-lg shadow-blue-500/20 active:scale-95 transition-all"
              >
                  <div className="flex items-center gap-3">
                      <div className="w-10 h-10 bg-white/20 rounded-2xl flex items-center justify-center">
                          {/* Updated: Using TelegramIcon component from common/icons */}
                          <TelegramIcon className="text-2xl" />
                      </div>
                      <div className="text-right">
                          <p className="text-xs opacity-80 font-bold">المحتوى الإبداعي</p>
                          <p className="font-black">تحميل الصور والفيديو بدقة عالية</p>
                      </div>
                  </div>
                  <ChevronDownIcon className="w-5 h-5 -rotate-90" />
              </a>
          )}
      </div>

      {/* 8. Fixed Action Bottom Bar */}
      <div className="fixed bottom-0 left-0 right-0 p-4 bg-white/80 dark:bg-slate-900/80 backdrop-blur-xl border-t border-gray-100 dark:border-gray-800 z-50">
          <div className="max-w-lg mx-auto flex items-center gap-3">
              {/* Quantity Selector */}
              <div className="flex items-center bg-gray-100 dark:bg-gray-800 p-1 rounded-2xl border border-gray-200 dark:border-gray-700 h-14">
                  <button onClick={() => setQuantity(q => q + 1)} disabled={quantity >= product.stock} className="w-10 h-full flex items-center justify-center text-primary disabled:opacity-30"><PlusIcon className="w-4 h-4" /></button>
                  <span className="w-10 text-center font-black dark:text-white">{quantity}</span>
                  <button onClick={() => setQuantity(q => Math.max(1, q - 1))} className="w-10 h-full flex items-center justify-center text-gray-400"><MinusIcon className="w-4 h-4" /></button>
              </div>

              {/* Add to Cart Button */}
              <button 
                onClick={handleAddToCart}
                disabled={product.stock === 0}
                className="flex-grow bg-primary text-white h-14 rounded-2xl font-black shadow-xl shadow-primary/30 active:scale-95 transition-all flex items-center justify-center gap-2 disabled:bg-gray-300"
              >
                  <CartIcon className="w-5 h-5" />
                  <span>{product.stock === 0 ? 'نفذت الكمية' : 'إضافة السيريات للسلة'}</span>
              </button>
          </div>
      </div>

      <style>{`
          @keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
          .animate-fade-in { animation: fade-in 0.2s ease-out forwards; }
          .no-scrollbar::-webkit-scrollbar { display: none; }
          .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
    </div>
  );
};

export default ProductDetailsPage;
